import { checkEndpointSchema } from '@agentcash/discovery';

import { log } from '@/shared/log';

import { buildRequestHeaders } from '@/shared/request/build';

import type {
  RequestContext,
  RequestInput,
  RequestMethod,
} from '@/shared/request/types';
import { safeParseJson, safeToJsonObject } from '@/shared/neverthrow/json';

type CheckRequestInput = Omit<RequestInput, 'method'> & {
  method?: RequestMethod;
};

export async function checkEndpoint(
  surface: string,
  requestInput: CheckRequestInput,
  context: RequestContext
) {
  const { url, method, body } = requestInput;
  log.info('Checking endpoint', {
    surface,
    url,
    method,
    hasSampleInputBody: !!body,
  });

  const requestHeaders = buildRequestHeaders(requestInput.headers, context);

  const result = await checkEndpointSchema({
    url,
    sampleInputBody: body
      ? safeParseJson(surface, body).match(
          json => json as Record<string, unknown>,
          () => undefined
        )
      : undefined,
    headers: Object.fromEntries(requestHeaders.entries()),
  });

  if (!result.found) {
    log.error(`[checkEndpoint failed`, {
      surface,
      url,
      cause: result.cause,
      message: result.message,
    });
    return result;
  }

  const advisories = method
    ? result.advisories.filter(a => (a.method as RequestMethod) === method)
    : result.advisories;

  return {
    ...result,
    advisories: advisories.map(a => ({
      ...a,
      inputSchema: safeToJsonObject(surface, a.inputSchema).match(
        json => json,
        () => undefined
      ),
      outputSchema: safeToJsonObject(surface, a.outputSchema).match(
        json => json,
        () => undefined
      ),
      paymentOptions: safeToJsonObject(surface, a.paymentOptions).match(
        json => json,
        () => undefined
      ),
      paymentRequiredBody: safeToJsonObject(
        surface,
        a.paymentRequiredBody
      ).match(
        json => json,
        () => undefined
      ),
      requiresPayment: a.authMode === 'paid' || a.authMode === 'apiKey+paid',
    })),
  };
}
